	/**
	 * @param \WebPage $oPage
	 * @param bool $bEditMode
	 */
	public function DisplayBareRelations(WebPage $oPage, $bEditMode = false)
	{
		parent::DisplayBareRelations($oPage, $bEditMode);

		if ($bEditMode) {
            return;
        }

        $sUrl = trim((string) $this->Get('dataviz_url')); // code attribut Rack

        if ($sUrl === '') {
            return;
        }

		$oPage->SetCurrentTab(Dict::S('EnterpriseEVoViewInRack:tab'));
        if (!preg_match('#^https?://#i', $sUrl)) {
            $oPage->p('URL invalide ou non autorisée.');
            return;
        }

        $sUrlEscaped = utils::EscapeHtml($sUrl);

        $oPage->Add("
            <div style=\"height:80vh; width:100%;\">
                <iframe
                    src=\"$sUrlEscaped\"
                    style=\"width:100%; height:100%; border:0;\"
                    loading=\"lazy\"
                    referrerpolicy=\"no-referrer\">
                </iframe>
            </div>
        ");
	}
